member.example:
This is a sample of how to use this class.

// Get the style
var style = ShapeStyleHelper.GetStyle(shape1);

// Modify the style
style["position"] = "absolute";
style["margin-left"] = "0";

// Set the style
ShapeStyleHelper.SetStyle(shape1, style);

example.code:
using WordDocument document = WordDocument.Create(filePath);

WordList list = document.AddCustomBulletList(
    WordListLevelKind.BulletSquareSymbol,
    "Courier New",
    OfficeIMO.Drawing.OfficeColor.Red,
    fontSize: 16);

list.AddItem("Custom bullet item");
document.Save();

using WordDocument document = WordDocument.Create(filePath);

WordList list = document.AddCustomList()
    .AddListLevel(1, WordListLevelKind.BulletSquareSymbol, "Courier New", colorHex: "#FF0000", fontSize: 14)
    .AddListLevel(5, WordListLevelKind.BulletBlackCircle, "Arial", colorHex: "#00FF00", fontSize: 10);

list.AddItem("First level item");
list.AddItem("Fifth level item", 4);
document.Save();

WordList list = document.AddCustomList();
list.Numbering.AddLevel(new WordListLevel(WordListLevelKind.Decimal));
list.SetStartNumberingValue(3);
list.AddItem("Starts at three");

WordList list = document.AddCustomList()
    .AddListLevel(1, WordListLevelKind.BulletSquareSymbol, "Courier New", colorHex: "#FF0000", fontSize: 14)
    .AddListLevel(2, WordListLevelKind.BulletBlackCircle, "Arial", colorHex: "#00FF00", fontSize: 10);

list.AddItem("Top level");
list.AddItem("Nested level", 1);

WordList list = document.AddCustomList();
WordListLevel level = new WordListLevel(WordListLevelKind.Decimal)
    .SetStartNumberingValue(3);

list.Numbering.AddLevel(level);
list.AddItem("Starts at three");

