example.code:
Style style = new() {
    Type = StyleValues.Paragraph,
    StyleId = "MyStyle"
};

WordParagraphStyle.RegisterCustomStyle("MyStyle", style);
document.AddParagraph("Hello world").SetStyleId("MyStyle");

Style style = new() {
    Type = StyleValues.Paragraph,
    StyleId = "MyStyle"
};

WordParagraphStyle.RegisterCustomStyle("MyStyle", style);

using WordDocument document = WordDocument.Create(filePath);
document.AddParagraph("Hello world").SetStyleId("MyStyle");
document.Save();
